            string value = param.Value.ToString();
            if (!string.IsNullOrEmpty(value))
            {
                if (value.Contains(","))
                {
                    var values = value.Split(',');
                    var inClause = new StringBuilder();
                    inClause.Append($" AND {param.Key} IN (");
                    for (int i = 0; i < values.Length; i++)
                    {
                        if (i > 0) inClause.Append(",");
                        inClause.Append($"'{values[i]}'");
                    }
                    inClause.Append(")");
                    queryBuilder.Append(inClause.ToString());
                }
                else if (value.StartsWith(">") || value.StartsWith("<") || value.StartsWith(">=") || value.StartsWith("<="))
                {
                    string op = value.StartsWith(">=") || value.StartsWith("<=") ? value.Substring(0, 2) : value.Substring(0, 1);
                    string val = value.Substring(op.Length);
                    queryBuilder.Append($" AND {param.Key} {op} '{val}'");
                }
                else if (value.Contains("*") || value.Contains("%"))
                {
                    value = value.Replace("*", "%");
                    queryBuilder.Append($" AND {param.Key} LIKE '{value}'");
                }
                else
                {
                    queryBuilder.Append($" AND {param.Key} = '{value}'");
                }
            }
        }

        string selectColumns = req.Query["select"];
        if (!string.IsNullOrEmpty(selectColumns))
        {
            queryBuilder.Replace("SELECT *", $"SELECT {selectColumns}");
        }

        string orderBy = req.Query["orderby"];
        if (!string.IsNullOrEmpty(orderBy))
        {
            queryBuilder.Append($" ORDER BY {orderBy}");
        }

        string limit = req.Query["limit"];
        string offset = req.Query["offset"];
        if (!string.IsNullOrEmpty(limit))
        {
            if (!string.IsNullOrEmpty(offset))
            {
                queryBuilder.Append($" OFFSET {offset} ROWS FETCH NEXT {limit} ROWS ONLY");
            }
            else
            {
                queryBuilder.Append($" OFFSET 0 ROWS FETCH NEXT {limit} ROWS ONLY");
            }
        }

        string sqlQuery = queryBuilder.ToString();
        log.LogInformation($"Executing query: {sqlQuery}");

        var results = new List<Dictionary<string, object>>();

        try
        {
            using (SqlConnection connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();

                using (SqlCommand command = new SqlCommand(sqlQuery, connection))
                {
                    command.CommandTimeout = 30;

                    using (SqlDataReader reader = await command.ExecuteReaderAsync())
                    {
                        while (await reader.ReadAsync())
                        {
                            var row = new Dictionary<string, object>();
