                            {
                                row[reader.GetName(i)] = reader.IsDBNull(i) ? null : reader.GetValue(i);
                            }
                            results.Add(row);
                        }
                    }
                }
            }

            return new OkObjectResult(new
            {
                count = results.Count,
                data = results
            });
        }
        catch (SqlException ex)
        {
            log.LogError($"SQL Error: {ex.Message}");
